import { describe, expect, it } from 'vitest';
import { createLessonPlaybackMachine } from '../../src/tutor/lesson_playback';

describe('LessonPlaybackMachine', () => {
  it('supports pause and resume without changing lesson scope', () => {
    const machine = createLessonPlaybackMachine({ sessionId: 'sess-1', childId: 'child-1', guardianId: 'guardian-1', lessonId: 'lesson-1', mode: 'child', startedBy: 'guardian', status: 'active' });
    machine.start();
    machine.pause();
    machine.resume();
    expect(machine.snapshot().lessonId).toBe('lesson-1');
    expect(machine.snapshot().state).toBe('presenting');
  });

  it('marks interrupt explicitly for guardian takeover', () => {
    const machine = createLessonPlaybackMachine({ sessionId: 'sess-1', childId: 'child-1', guardianId: 'guardian-1', lessonId: 'lesson-1', mode: 'child', startedBy: 'guardian', status: 'active' });
    machine.start();
    machine.interrupt('guardian_review');
    expect(machine.snapshot().state).toBe('interrupted');
    expect(machine.snapshot().reason).toBe('guardian_review');
  });
});

