import type { SessionEnvelope } from './session_envelope';

export type LessonPlaybackState = 'idle' | 'presenting' | 'paused' | 'interrupted' | 'completed';

export interface LessonPlaybackSnapshot {
  state: LessonPlaybackState;
  lessonId: string;
  cursor: number;
  reason?: string;
}

export function createLessonPlaybackMachine(envelope: SessionEnvelope) {
  return {
    start() {},
    pause() {},
    resume() {},
    interrupt(_reason: string) {},
    snapshot(): LessonPlaybackSnapshot {
      return { state: 'idle', lessonId: envelope.lessonId, cursor: 0 };
    }
  };
}
